public class SessionManager
{
    private string sessionDirectory;
    private Dictionary<string, UserSession> activeSessions;
    private int sessionTimeoutMinutes;

    public SessionManager(string sessionDirectory, int sessionTimeoutMinutes = 30)
    {
        this.sessionDirectory = sessionDirectory;
        this.sessionTimeoutMinutes = sessionTimeoutMinutes;
        this.activeSessions = new Dictionary<string, UserSession>();

        if (!Directory.Exists(sessionDirectory))
        {
            Directory.CreateDirectory(sessionDirectory);
        }
    }

    public UserSession CreateSession(string userId)
    {
