        activeSessions[session.SessionId] = session;
        SaveSession(session);
        return session;
    }

    public UserSession GetSession(string sessionId)
    {
        if (activeSessions.ContainsKey(sessionId))
        {
            var session = activeSessions[sessionId];
            if (!session.IsExpired(sessionTimeoutMinutes))
            {
                session.UpdateLastAccess();
                SaveSession(session);
                return session;
            }
            else
            {
                DestroySession(sessionId);
                return null;
            }
        }

        var loadedSession = LoadSession(sessionId);
        if (loadedSession != null && !loadedSession.IsExpired(sessionTimeoutMinutes))
        {
            loadedSession.UpdateLastAccess();
            activeSessions[sessionId] = loadedSession;
            SaveSession(loadedSession);
            return loadedSession;
        }

        return null;
    }

    public void SaveSession(UserSession session)
    {
        string filePath = GetSessionFilePath(session.SessionId);
        using (FileStream fs = new FileStream(filePath, FileMode.Create))
        {
            BinaryFormatter formatter = new BinaryFormatter();
            formatter.Serialize(fs, session);
        }
    }

    public UserSession LoadSession(string sessionId)
    {
        string filePath = GetSessionFilePath(sessionId);
        if (!File.Exists(filePath))
        {
            return null;
        }

        try
        {
            using (FileStream fs = new FileStream(filePath, FileMode.Open))
            {
                BinaryFormatter formatter = new BinaryFormatter();
                return (UserSession)formatter.Deserialize(fs);
            }
        }
        catch
        {
            return null;
        }
    }

    public void DestroySession(string sessionId)
    {
        activeSessions.Remove(sessionId);
        string filePath = GetSessionFilePath(sessionId);
        if (File.Exists(filePath))
        {
            File.Delete(filePath);
        }
    }

    public void CleanupExpiredSessions()
    {
        var files = Directory.GetFiles(sessionDirectory, "*.session");
        foreach (var file in files)
        {
            try
