                using (FileStream fs = new FileStream(file, FileMode.Open))
                {
                    BinaryFormatter formatter = new BinaryFormatter();
                    var session = (UserSession)formatter.Deserialize(fs);
                    if (session.IsExpired(sessionTimeoutMinutes))
